// Input: { angle_id, angle_title, p1_persona, p2_pain, p3_moment, p4_promise, p5_proof, p6_pull, product_name, product_image_url }
const d = $input.first().json;

// Build 6 distinct visual prompts from angle data
const baseStyle = 'photorealistic product advertisement, Vietnamese female model, clean white background, professional lighting, high quality 8k, sharp focus';
const productName = d.product_name || 'skincare product';
const pain = d.p2_pain || 'skin problem';
const promise = d.p4_promise || 'radiant skin';
const persona = d.p1_persona || 'Vietnamese woman 25-35';

const prompts = [
  {
    id: 'hook_before',
    label: 'Hook — Before State',
    prompt: `${persona} looking frustrated touching face, ${pain}, bathroom mirror, natural light, ${baseStyle}, --ar 4:5`,
    negative: 'ugly, blurry, low quality, text overlay, watermark'
  },
  {
    id: 'hook_after',
    label: 'Hook — After Transformation',
    prompt: `${persona} confident radiant smile, glowing skin, holding ${productName}, ${promise}, soft warm lighting, ${baseStyle}, --ar 4:5`,
    negative: 'ugly, blurry, low quality, text overlay, watermark'
  },
  {
    id: 'product_hero',
    label: 'Product Hero Shot',
    prompt: `${productName} product bottle on marble surface, beauty editorial photography, bokeh background, luxury skincare, ${baseStyle}, --ar 1:1`,
    negative: 'person, model, ugly, blurry, text'
  },
  {
    id: 'lifestyle_use',
    label: 'Lifestyle — In Use',
    prompt: `${persona} applying ${productName} morning routine, bathroom vanity, golden hour light, authentic lifestyle, ${baseStyle}, --ar 4:5`,
    negative: 'ugly, blurry, low quality, staged'
  },
  {
    id: 'proof_social',
    label: 'Social Proof — Crowd',
    prompt: `group of happy Vietnamese women beautiful skin, diverse ages 20-40, bright studio, ${productName} product visible, ${baseStyle}, --ar 16:9`,
    negative: 'ugly, blurry, fake looking'
  },
  {
    id: 'cta_urgency',
    label: 'CTA — Urgency',
    prompt: `${persona} excited pointing at ${productName} product, vibrant colors, energetic pose, e-commerce style, clean background, ${baseStyle}, --ar 4:5`,
    negative: 'ugly, blurry, text overlay'
  }
];

return prompts.map(p => ({
  json: {
    ...p,
    angle_id: d.angle_id,
    angle_title: d.angle_title,
    product_image_url: d.product_image_url || '',
    workspace_id: d.workspace_id || 'default'
  }
}));

// Poll ComfyUI for result URL
const promptId = $input.first().json.prompt_id;
const baseUrl = process.env.COMFYUI_BASE_URL;
const imageId = $input.first().json.id;
const angleId = $input.first().json.angle_id;

// ComfyUI saves to output folder — build the expected filename
const filename = `aios_${angleId}_${imageId}_00001_.png`;

return [{
  json: {
    prompt_id: promptId,
    image_filename: filename,
    image_url: `${baseUrl}/view?filename=${encodeURIComponent(filename)}&type=output`,
    ...$input.first().json
  }
}];

// Wait for ComfyUI to finish (poll history endpoint)
const promptId = $input.first().json.prompt_id;
const baseUrl = process.env.COMFYUI_BASE_URL;

try {
  const res = await $http.request({ url: `${baseUrl}/history/${promptId}`, method: 'GET' });
  const history = res.data;
  if (history && history[promptId] && history[promptId].status && history[promptId].status.completed) {
    return [{ json: { ready: true, ...$input.first().json } }];
  }
} catch(e) {}

return [{ json: { ready: false, ...$input.first().json } }];

// Collect all 6 image hashes returned by FB
const items = $input.all();
const imageHashes = items.map(i => ({
  id: i.json.id,
  label: i.json.label,
  hash: i.json.images ? Object.values(i.json.images)[0]?.hash : null,
  angle_id: i.json.angle_id,
  angle_title: i.json.angle_title,
  workspace_id: i.json.workspace_id
}));

return [{
  json: {
    success: true,
    angle_id: items[0].json.angle_id,
    angle_title: items[0].json.angle_title,
    workspace_id: items[0].json.workspace_id,
    image_count: imageHashes.filter(h => h.hash).length,
    images: imageHashes,
    fb_ad_account: process.env.FB_AD_ACCOUNT_ID,
    generated_at: new Date().toISOString()
  }
}];
